; TL072 Non-Inverting Amplifier
; U1: TL072 (single-supply OK)
; R1: 1kΩ (feedback)
; R2: 100Ω (ground)
; VIN: +IN (Pin 3)
; VOUT: -OUT (Pin 1)

; Op-Amp Symbol (TL072)
symbol TL072 {
    pins {
        (8, 10mm) +V;  // V+
        (4, 10mm) -V;  // V-
        (3, 10mm) +IN; // +IN (VIN)
        (2, 10mm) -IN; // -IN (feedback)
        (1, 10mm) -OUT; // -OUT (VOUT)
    }
    text "TL072" at (0, -15mm)
}

; Resistor Symbols
symbol R1 {
    text "1kΩ" at (0, 0)
}
symbol R2 {
    text "100Ω" at (0, 0)
}

; Net Definitions
net VIN {
    pin TL072 +IN;
    pin R1 1;  // Connects to VIN (external)
}
net VOUT {
    pin TL072 -OUT;
    pin R1 2;  // Feedback node
}
net GND {
    pin TL072 -V;
    pin R1 3;  // R1's other end
    pin R2 1;  // R2's top
}
net R2_GND {
    pin R2 2;  // R2's bottom (GND)
}

; Components
component U1 {
    symbol TL072;
    net VIN +IN;
    net VOUT -OUT;
    net VCC +V;
    net GND -V;
}
component R1 {
    symbol R1;
    net VIN 1;
    net VOUT 2;
}
component R2 {
    symbol R2;
    net VOUT 1;
    net GND 2;
}

; Connections
connect U1 +IN to VIN;
connect U1 -OUT to VOUT;
connect U1 +V to VCC;
connect U1 -V to GND;
connect R1 3 to GND;
connect R2 1 to VOUT;
connect R2 2 to GND;
```

